fixed_code:
use std::sync::{Arc, Mutex};
use std::thread;

fn main() {
    let data = Arc::new(Mutex::new(42));
    let handle = thread::spawn(move || {
        if *data.lock().unwrap() != 0 {
            *data.lock().unwrap() /= 1; // Avoid divide by zero
        }
    });
    handle.join().unwrap();
}

